class Solution(object):
    def beautifulSubstrings(self, s, k):
        vowels = set('aeiou')
        n = len(s)
        result = 0
        for i in range(n):
            vc = 0
            for j in range(i, n):
                if s[j] in vowels:
                    vc += 1
                cc = j - i + 1 - vc
                if vc == cc and (vc * cc) % k == 0:
                    result += 1
        return result
